 * Returns an object with `allowed` (boolean) and optional `reason` (string).
 */
export function checkPermission(
  toolName: string,
  config: { allowedTools?: string[]; blockedTools?: string[] }
): { allowed: boolean; reason?: string } {
  const { allowedTools, blockedTools } = config;

  if (blockedTools?.includes(toolName)) {
    return { allowed: false, reason: `Tool "${toolName}" is in the blocked list` };
  }

  if (allowedTools && !allowedTools.includes(toolName)) {
