import * as readline from "readline";

/**
 * Prompts the user in the terminal for a yes/no answer.
 */
async function askUser(question: string): Promise<boolean> {
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
  });
  return new Promise((resolve) => {
    rl.question(question, (answer) => {
      rl.close();
      resolve(answer.trim().toLowerCase().startsWith("y"));
    });
  });
}

/**
 * Core agent loop.
 */
export async function runAgent(userMessage: string): Promise<void> {
  const config = getConfig();

  logAuditEvent({
    timestamp: new Date().toISOString(),
    type: "agent_start",
    message: userMessage,
  });

  const client = new Anthropic();

  const messages: Anthropic.MessageParam[] = [
    { role: "user", content: userMessage },
  ];

  // ── Main agentic loop ────────────────────────────────────────────────────
  while (true) {
    const response = await client.messages.create({
      model: config.model,
      max_tokens: config.maxTokens,
      system: config.systemPrompt,
      tools: TOOLS as Anthropic.Tool[],
      messages,
    });

    // Push assistant turn
    messages.push({ role: "assistant", content: response.content });

    // ── End conditions ───────────────────────────────────────────────────
    if (response.stop_reason === "end_turn") {
      const textBlock = response.content.find((b) => b.type === "text");
      if (textBlock && textBlock.type === "text") {
        console.log("\n[Agent]:", textBlock.text);
      }
      break;
    }

    if (response.stop_reason !== "tool_use") {
      console.warn("[Agent] Unexpected stop reason:", response.stop_reason);
      break;
    }

    // ── Process tool calls ───────────────────────────────────────────────
    const toolResults: Anthropic.ToolResultBlockParam[] = [];

    for (const block of response.content) {
      if (block.type !== "tool_use") continue;

      const toolName = block.name;
      const toolArgs = block.input as Record<string, unknown>;

      // 1. Audit the call
      auditToolCall(toolName, toolArgs);

      // 2. Permission gate
      const permission = getToolPermission(toolName);
      if (!permission) {
        const msg = `Tool "${toolName}" not found in permissions map.`;
        console.warn(`[Agent] ${msg}`);
        auditPermissionDenied(toolName, "Tool not found in permissions map");
        toolResults.push({ type: "tool_result", tool_use_id: block.id, content: msg });
        continue;
      }

      const permCheck = checkPermission(toolName, config);
      if (!permCheck.allowed) {
        const msg = permCheck.reason ?? "Permission check failed";
        console.warn(`[Agent] ${msg}`);
        auditPermissionDenied(toolName, "Permission check failed");
        toolResults.push({ type: "tool_result", tool_use_id: block.id, content: msg });
        continue;
      }

      // 3. Approval gate (for write/execute tools)
      if (requiresApproval(toolName)) {
        const preview = JSON.stringify(toolArgs, null, 2).slice(0, 300);
        const question = `\n[Approval needed] Tool: ${toolName}\nArgs: ${preview}\nAllow? (y/n): `;
